class Stack:
    def __init__(self, capacity=100):
        self.a = [None] * capacity
        self.top = 0

    def push(self, x):
        self.a[self.top] = x
        self.top += 1

    def peek(self):
        return self.a[self.top - 1]

    def pop(self):
        self.top -= 1
        return self.a[self.top]

    def is_empty(self):
        return self.top == 0

    def is_full(self):
        return self.top == len(self.a)

