from collections import deque

def bfs_order(graph, start):
    q = deque([start])
    seen = {start}
    order = []
    while q:
        node = q.popleft()
        order.append(node)
        for nb in graph[node]:
            if nb not in seen:
                seen.add(nb)
                q.append(nb)
    return order

from collections import deque

def maxwin(nums, k):
    d = deque()
    out = []
    for i, x in enumerate(nums):
        while d and nums[d[-1]] <= x:
            d.pop()
        d.append(i)
        if d[0] <= i - k:
            d.popleft()
        if i >= k - 1:
            out.append(nums[d[0]])
    return out
